import React, { forwardRef, useImperativeHandle, useMemo, useRef, useState } from "react";
import { Pressable, Text, TextInput, View } from "react-native";
import type {
  PaginatorContext,
  PaginatorPageChangeEvent,
  PaginatorProps,
  PaginatorTemplateOptions,
  PassThroughType,
} from "./Paginator.types";
export type {
  PaginatorContext,
  PaginatorPageChangeEvent,
  PaginatorProps,
  PaginatorTemplateOptions,
  PassThroughType,
} from "./Paginator.types";

type PaginatorRef = {
  getElement: () => View | null;
};

const DEFAULT_LAYOUT =
  "FirstPageLink PrevPageLink PageLinks NextPageLink LastPageLink RowsPerPageDropdown";

function resolvePT<T extends object>(
  ptValue: PassThroughType<T> | undefined,
  options: { props: PaginatorProps; context: PaginatorContext },
): T | undefined {
  if (!ptValue) return undefined;
  return typeof ptValue === "function" ? ptValue(options) : ptValue;
}

function clamp(n: number, min: number, max: number) {
  return Math.max(min, Math.min(max, n));
}

function formatReport(tpl: string, vars: Record<string, number>) {
  return tpl.replace(/\{(\w+)\}/g, (_, k) => String(vars[k] ?? `{${k}}`));
}

function getTemplateObj(template: PaginatorProps["template"]): PaginatorTemplateOptions | undefined {
  if (!template) return undefined;
  if (typeof template === "string") return { layout: template };
  return template;
}

function parseLayout(templateObj?: PaginatorTemplateOptions) {
  return (templateObj?.layout ?? DEFAULT_LAYOUT)
    .split(/\s+/)
    .map((t: string) => t.trim())
    .filter(Boolean);
}

/** --- Token: RowsPerPageDropdown (stateful) --- */
function RowsPerPageDropdownToken({
                                    props,
                                    templateObj,
                                    unstyled,
                                    disabled,
                                    currentPageOne,
                                    pageCount,
                                    totalRecords,
                                    rows,
                                    rowsPerPageOptions,
                                    goTo,
                                    pt,
                                  }: {
  props: PaginatorProps;
  templateObj?: PaginatorTemplateOptions;
  unstyled?: boolean;
  disabled: boolean;
  currentPageOne: number;
  pageCount: number;
  totalRecords: number;
  rows: number;
  rowsPerPageOptions?: number[];
  goTo: (first: number, rows: number) => void;
  pt?: PaginatorProps["pt"];
}) {
  const [open, setOpen] = useState(false);

  const context: PaginatorContext = { active: false, disabled };
  const ptDrop = resolvePT(pt?.RPPDropdown, { props, context });

  const options = (rowsPerPageOptions ?? [])
    .map((n) => Number(n))
    .filter((n) => Number.isFinite(n) && n > 0);

  const element = (
    <View className={unstyled ? "" : "relative"} {...ptDrop}>
      <Pressable
        accessibilityRole="button"
        accessibilityLabel="Rows Per Page"
        disabled={disabled}
        onPress={() => setOpen((v) => !v)}
        className={unstyled ? "" : "px-2 py-1 rounded border"}
      >
        <Text>{rows || options[0] || 0}</Text>
      </Pressable>

      {open && !disabled && (
        <View className={unstyled ? "" : "mt-2 border rounded p-2"}>
          {options.map((opt) => (
            <Pressable
              key={opt}
              accessibilityRole="button"
              onPress={() => {
                setOpen(false);
                // PrimeReact behavior: changing rows typically resets to start
                goTo(0, opt);
              }}
              className={unstyled ? "" : "py-1 px-2 rounded"}
            >
              <Text>{opt}</Text>
            </Pressable>
          ))}
        </View>
      )}
    </View>
  );

  const custom = templateObj?.RowsPerPageDropdown;
  if (typeof custom === "function") {
    return custom({
      value: rows,
      options,
      onChange: (nextValue: any) => goTo(0, Number(nextValue)),
      appendTo: props.dropdownAppendTo,
      currentPage: currentPageOne,
      totalPages: pageCount,
      totalRecords,
      element: element as any,
      props,
      disabled,
    });
  }
  return (custom as any) ?? element;
}

/** --- Token: JumpToPageInput (stateful) --- */
function JumpToPageInputToken({
                                props,
                                templateObj,
                                unstyled,
                                disabled,
                                currentPageOne,
                                pageCount,
                                rows,
                                goTo,
                                pt,
                              }: {
  props: PaginatorProps;
  templateObj?: PaginatorTemplateOptions;
  unstyled?: boolean;
  disabled: boolean;
  currentPageOne: number;
  pageCount: number;
  rows: number;
  goTo: (first: number, rows: number) => void;
  pt?: PaginatorProps["pt"];
}) {
  // Keep a local string so user can type freely; sync on page change.
  const [value, setValue] = useState(String(currentPageOne));

  React.useEffect(() => {
    setValue(String(currentPageOne));
  }, [currentPageOne]);

  const context: PaginatorContext = { active: false, disabled };
  const ptInput = resolvePT(pt?.JTPInput, { props, context });

  const element = (
    <TextInput
      keyboardType="number-pad"
      value={value}
      onChangeText={setValue}
      onSubmitEditing={() => {
        const n = Number(value);
        if (!Number.isFinite(n)) return;
        const p = clamp(n - 1, 0, Math.max(0, pageCount - 1));
        goTo(p * rows, rows);
      }}
      editable={!disabled}
      className={unstyled ? "" : "min-w-[48px] px-2 py-1 border rounded"}
      {...ptInput}
    />
  );

  const custom = templateObj?.JumpToPageInput;
  if (typeof custom === "function") {
    return custom({
      value: currentPageOne,
      onChange: (nextFirst: number, nextRows: number) => goTo(nextFirst, nextRows),
      disabled,
      className: "",
      element: element as any,
      props,
    });
  }
  return (custom as any) ?? element;
}

/** --- Token: PageLinks (stateless) --- */
function PageLinksToken({
                          props,
                          templateObj,
                          unstyled,
                          isDisabled,
                          view,
                          currentPageZero,
                          currentPageOne,
                          pageCount,
                          totalRecords,
                          rows,
                          goTo,
                          pt,
                        }: {
  props: PaginatorProps;
  templateObj?: PaginatorTemplateOptions;
  unstyled?: boolean;
  isDisabled: boolean;
  view: { startPage: number; endPage: number };
  currentPageZero: number;
  currentPageOne: number;
  pageCount: number;
  totalRecords: number;
  rows: number;
  goTo: (first: number, rows: number) => void;
  pt?: PaginatorProps["pt"];
}) {
  const ptPages = resolvePT(pt?.pages, { props, context: { active: false, disabled: isDisabled } });

  const pages = [];
  for (let p = view.startPage; p <= view.endPage; p++) {
    const active = p === currentPageZero;
    const context: PaginatorContext = { active, disabled: isDisabled };
    const ptBtn = resolvePT(pt?.pageButton, { props, context });

    const onClick = () => goTo(p * rows, rows);
    pages.push(
      <Pressable
        key={p}
        accessibilityRole="button"
        accessibilityLabel={`Page ${p + 1}`}
        accessibilityState={{ selected: active, disabled: isDisabled }}
        disabled={isDisabled}
        onPress={onClick}
        className={unstyled ? "" : `px-2 py-1 rounded ${active ? "font-bold" : ""}`}
        {...ptBtn}
      >
        <Text>{p + 1}</Text>
      </Pressable>,
    );
  }

  const defaultEl = (
    <View className={unstyled ? "" : "flex-row items-center gap-1"} {...ptPages}>
      {pages}
    </View>
  );

  const custom = templateObj?.PageLinks;
  if (typeof custom === "function") {
    return custom({
      onClick: () => {},
      className: "",
      view,
      page: currentPageZero,
      currentPage: currentPageOne,
      totalPages: pageCount,
      totalRecords,
      rows,
      element: defaultEl as any,
      props,
    });
  }

  return (custom as any) ?? defaultEl;
}

export const Paginator = forwardRef<PaginatorRef, PaginatorProps>((props, ref) => {
  const {
    totalRecords = 0,
    rows = 0,
    first = 0,
    pageLinkSize = 5,
    rowsPerPageOptions,
    alwaysShow,
    template,
    leftContent,
    rightContent,
    firstPageLinkIcon,
    prevPageLinkIcon,
    nextPageLinkIcon,
    lastPageLinkIcon,
    currentPageReportTemplate = "({currentPage} of {totalPages})",
    onPageChange,
    pt,
    unstyled,
    className,
    ...rootProps
  } = props;

  const rootRef = useRef<View>(null);
  useImperativeHandle(ref, () => ({ getElement: () => rootRef.current }));

  const pageCount = useMemo(() => {
    if (!rows || rows <= 0) return 0;
    return Math.ceil(totalRecords / rows);
  }, [rows, totalRecords]);

  const currentPageZero = useMemo(() => {
    if (!rows || rows <= 0) return 0;
    return clamp(Math.floor(first / rows), 0, Math.max(0, pageCount - 1));
  }, [first, rows, pageCount]);

  const currentPageOne = currentPageZero + 1;

  // PrimeReact behavior: hide when <= 1 page unless alwaysShow

  const templateObj = getTemplateObj(template);
  const layoutTokens = parseLayout(templateObj);

  const goTo = (nextFirst: number, nextRows: number) => {
    const safeRows = nextRows > 0 ? nextRows : rows;
    const safePageCount = safeRows > 0 ? Math.ceil(totalRecords / safeRows) : 0;

    const maxFirst = Math.max(0, (safePageCount - 1) * safeRows);
    const safeFirst = clamp(nextFirst, 0, maxFirst);

    const ev: PaginatorPageChangeEvent = {
      first: safeFirst,
      rows: safeRows,
      page: safeRows > 0 ? Math.floor(safeFirst / safeRows) : 0,
      pageCount: safePageCount,
    };

    onPageChange?.(ev);
  };

  const isDisabled = pageCount <= 0 || rows <= 0;
  const isFirst = currentPageZero <= 0;
  const isLast = currentPageZero >= pageCount - 1;

  // Window around current page like PrimeReact
  const view = useMemo(() => {
    const size = Math.max(1, pageLinkSize);
    const half = Math.floor(size / 2);

    let startPage = currentPageZero - half;
    let endPage = currentPageZero + half;

    if (size % 2 === 0) endPage -= 1;

    if (startPage < 0) {
      endPage += -startPage;
      startPage = 0;
    }
    if (endPage > pageCount - 1) {
      const overflow = endPage - (pageCount - 1);
      startPage = Math.max(0, startPage - overflow);
      endPage = pageCount - 1;
    }

    return { startPage, endPage };
  }, [currentPageZero, pageCount, pageLinkSize]);

  if (!alwaysShow && pageCount <= 1) return null;

  const baseRootClass = unstyled ? "" : "flex-row items-center justify-between";
  const baseLeftClass = unstyled ? "" : "flex-row items-center gap-2";
  const baseRightClass = unstyled ? "" : "flex-row items-center gap-2";

  const ptRoot = resolvePT(pt?.root, { props, context: { active: false, disabled: isDisabled } });
  const ptLeft = resolvePT(pt?.left, { props, context: { active: false, disabled: isDisabled } });
  const ptEnd = resolvePT(pt?.end, { props, context: { active: false, disabled: isDisabled } });

  const renderToken = (token: string) => {
    switch (token) {
      case "FirstPageLink": {
        const disabled = isDisabled || isFirst;
        const context: PaginatorContext = { active: false, disabled };
        const ptBtn = resolvePT(pt?.firstPageButton, { props, context });

        const onClick = () => goTo(0, rows);
        const element = (
          <Pressable
            accessibilityRole="button"
            accessibilityLabel="First Page"
            disabled={disabled}
            onPress={onClick}
            className={unstyled ? "" : "px-2 py-1 rounded"}
            {...ptBtn}
          >
            <Text>{firstPageLinkIcon ?? "⏮"}</Text>
          </Pressable>
        );

        const custom = templateObj?.FirstPageLink;
        if (typeof custom === "function") {
          return custom({
            onClick,
            className: "",
            iconClassName: "",
            disabled,
            element,
            page: 0,
            currentPage: currentPageOne,
            totalPages: pageCount,
            totalRecords,
            rows,
            props,
          });
        }
        return (custom as any) ?? element;
      }

      case "PrevPageLink": {
        const disabled = isDisabled || isFirst;
        const context: PaginatorContext = { active: false, disabled };
        const ptBtn = resolvePT(pt?.prevPageButton, { props, context });

        const onClick = () => goTo((currentPageZero - 1) * rows, rows);
        const element = (
          <Pressable
            accessibilityRole="button"
            accessibilityLabel="Previous Page"
            disabled={disabled}
            onPress={onClick}
            className={unstyled ? "" : "px-2 py-1 rounded"}
            {...ptBtn}
          >
            <Text>{prevPageLinkIcon ?? "◀"}</Text>
          </Pressable>
        );

        const custom = templateObj?.PrevPageLink;
        if (typeof custom === "function") {
          return custom({
            onClick,
            className: "",
            iconClassName: "",
            disabled,
            element,
            page: Math.max(0, currentPageZero - 1),
            currentPage: currentPageOne,
            totalPages: pageCount,
            totalRecords,
            rows,
            props,
          });
        }
        return (custom as any) ?? element;
      }

      case "NextPageLink": {
        const disabled = isDisabled || isLast;
        const context: PaginatorContext = { active: false, disabled };
        const ptBtn = resolvePT(pt?.nextPageButton, { props, context });

        const onClick = () => goTo((currentPageZero + 1) * rows, rows);
        const element = (
          <Pressable
            accessibilityRole="button"
            accessibilityLabel="Next Page"
            disabled={disabled}
            onPress={onClick}
            className={unstyled ? "" : "px-2 py-1 rounded"}
            {...ptBtn}
          >
            <Text>{nextPageLinkIcon ?? "▶"}</Text>
          </Pressable>
        );

        const custom = templateObj?.NextPageLink;
        if (typeof custom === "function") {
          return custom({
            onClick,
            className: "",
            iconClassName: "",
            disabled,
            element,
            page: Math.min(pageCount - 1, currentPageZero + 1),
            currentPage: currentPageOne,
            totalPages: pageCount,
            totalRecords,
            rows,
            props,
          });
        }
        return (custom as any) ?? element;
      }

      case "LastPageLink": {
        const disabled = isDisabled || isLast;
        const context: PaginatorContext = { active: false, disabled };
        const ptBtn = resolvePT(pt?.lastPageButton, { props, context });

        const onClick = () => goTo(Math.max(0, (pageCount - 1) * rows), rows);
        const element = (
          <Pressable
            accessibilityRole="button"
            accessibilityLabel="Last Page"
            disabled={disabled}
            onPress={onClick}
            className={unstyled ? "" : "px-2 py-1 rounded"}
            {...ptBtn}
          >
            <Text>{lastPageLinkIcon ?? "⏭"}</Text>
          </Pressable>
        );

        const custom = templateObj?.LastPageLink;
        if (typeof custom === "function") {
          return custom({
            onClick,
            className: "",
            iconClassName: "",
            disabled,
            element,
            page: Math.max(0, pageCount - 1),
            currentPage: currentPageOne,
            totalPages: pageCount,
            totalRecords,
            rows,
            props,
          });
        }
        return (custom as any) ?? element;
      }

      case "PageLinks":
        return (
          <PageLinksToken
            props={props}
            templateObj={templateObj}
            unstyled={unstyled}
            isDisabled={isDisabled}
            view={view}
            currentPageZero={currentPageZero}
            currentPageOne={currentPageOne}
            pageCount={pageCount}
            totalRecords={totalRecords}
            rows={rows}
            goTo={goTo}
            pt={pt}
          />
        );

      case "RowsPerPageDropdown":
        return (
          <RowsPerPageDropdownToken
            props={props}
            templateObj={templateObj}
            unstyled={unstyled}
            disabled={isDisabled || !rowsPerPageOptions?.length}
            currentPageOne={currentPageOne}
            pageCount={pageCount}
            totalRecords={totalRecords}
            rows={rows}
            rowsPerPageOptions={rowsPerPageOptions}
            goTo={goTo}
            pt={pt}
          />
        );

      case "CurrentPageReport": {
        const firstIndex = totalRecords === 0 ? 0 : currentPageZero * rows + 1;
        const lastIndex = Math.min(totalRecords, (currentPageZero + 1) * rows);

        const text = formatReport(currentPageReportTemplate, {
          currentPage: currentPageOne,
          totalPages: pageCount,
          rows,
          first: firstIndex,
          last: lastIndex,
          totalRecords,
        });

        const context: PaginatorContext = { active: false, disabled: isDisabled };
        const ptCurrent = resolvePT(pt?.current, { props, context });

        const element = (
          <Text
            accessibilityLiveRegion="polite"
            className={unstyled ? "" : "px-2"}
            {...ptCurrent}
          >
            {text}
          </Text>
        );

        const custom = templateObj?.CurrentPageReport;
        if (typeof custom === "function") {
          return custom({
            currentPage: currentPageOne,
            totalPages: pageCount,
            first: firstIndex,
            last: lastIndex,
            rows,
            totalRecords,
            className: "",
            element: element as any,
            props,
          });
        }

        return (custom as any) ?? element;
      }

      case "JumpToPageInput":
        return (
          <JumpToPageInputToken
            props={props}
            templateObj={templateObj}
            unstyled={unstyled}
            disabled={isDisabled}
            currentPageOne={currentPageOne}
            pageCount={pageCount}
            rows={rows}
            goTo={goTo}
            pt={pt}
          />
        );

      default:
        return null;
    }
  };

  return (
    <View
      ref={rootRef}
      className={`${baseRootClass} ${className ?? ""}`}
      {...rootProps}
      {...ptRoot}
    >
      <View className={baseLeftClass} {...ptLeft}>
        {leftContent}
        {layoutTokens.map((t: string, i: any) => (
          <React.Fragment key={`${t}-${i}`}>{renderToken(t)}</React.Fragment>
        ))}
      </View>

      <View className={baseRightClass} {...ptEnd}>
        {rightContent}
      </View>
    </View>
  );
});

Paginator.displayName = "Paginator";
export default Paginator;
